/* Includes ------------------------------------------------------------------*/
#include "pressure_sensor.h"
#include "sensor.h"  // For extern volatile sensor_data_t sensor_data

/* Private defines -----------------------------------------------------------*/

/**
 * @brief Depth calculation coefficient (seawater)
 *
 * Derivation:
 * Pressure values are scaled ×100 for integer precision (e.g., 101325 = 1013.25 mbar)
 *
 * depth_m = delta_pressure_Pa / (ρ × g)
 * depth_m = (delta_pressure_scaled / 100) / (1025 kg/m³ × 9.80665 m/s² / 100)
 * depth_m = delta_pressure_scaled / 10052.816
 * depth_m ≈ delta_pressure_scaled × 0.0000995
 *
 * For millimeters:
 * depth_mm = depth_m × 1000
 * depth_mm ≈ delta_pressure_scaled × 0.0995
 *
 * Integer approximation (to avoid FPU):
 * depth_mm = (delta_pressure_scaled × 995) / 10000
 *
 * Example:
 * - At surface: delta = 0 → depth = 0 mm
 * - At 10m: delta = 100000 (1000 mbar × 100 scaling) → depth = 9950 mm ≈ 10 m
 */
#define DEPTH_COEFFICIENT_NUMERATOR     995    /*!< Numerator for depth calculation */
#define DEPTH_COEFFICIENT_DENOMINATOR   10000  /*!< Denominator: 100 (scaling) × 100 (mbar→m) */

/* Exported functions --------------------------------------------------------*/

/**
 * @brief Initialize pressure sensor data structure
 *
 * Sets initial values to atmospheric pressure at sea level and standard temperature.
 * Assumes device is at surface during initialization.
 *
 * @note This function accesses the global volatile sensor_data structure
 * @note Called once during system startup in main.c after sensor_init()
 */
void pressure_sensor_init(void)
{
    /* Initialize surface reference pressure (1013.25 mbar × 100) */
    sensor_data.pressure.surface_pressure_mbar = ATMOSPHERIC_PRESSURE_MBAR;

    /* Initialize current pressure to atmospheric (start at surface) */
    sensor_data.pressure.pressure_mbar = ATMOSPHERIC_PRESSURE_MBAR;

    /* Initialize temperature to standard value (30.00°C × 100) */
    sensor_data.pressure.temperature_c = STANDARD_TEMPERATURE_C;

    /* Initialize depth to zero (at surface) */
    sensor_data.pressure.depth_mm = 0;

    /* Set validity flag (data is valid) */
    sensor_data.pressure.pressure_valid = true;
}

/**
 * @brief Calculate depth from pressure difference using seawater formula
 *
 * Algorithm:
 * 1. Calculate pressure difference: delta_P = P_current - P_surface
 * 2. Apply seawater depth formula: depth_mm = (delta_P × 995) / 100
 *
 * Accuracy:
 * - Resolution: ~0.1 mm per 0.01 mbar pressure change
 * - Error: < 0.5% (comparison to IEEE seawater formula)
 *
 * @param current_pressure_mbar Current pressure reading (scaled × 100)
 * @param surface_pressure_mbar Surface reference pressure (scaled × 100)
 * @return Depth in millimeters (signed: positive = below, negative = above surface)
 *
 * @note Integer arithmetic only (no FPU usage)
 * @note Result range: ±2,147,483,647 mm (±2,147 km)
 * @note Overflow protected: max realistic diving depth 330m = 330,000 mm << INT32_MAX
 */
int32_t pressure_sensor_calculate_depth_mm(int32_t current_pressure_mbar, int32_t surface_pressure_mbar)
{
    /* Calculate pressure difference (signed) */
    int32_t delta_pressure_mbar =  surface_pressure_mbar - current_pressure_mbar;

    /* Apply seawater depth formula with integer arithmetic */
    /* depth_mm = (delta_pressure_mbar × 995) / 100 */
    int32_t depth_mm = (delta_pressure_mbar * DEPTH_COEFFICIENT_NUMERATOR) / DEPTH_COEFFICIENT_DENOMINATOR;

    return depth_mm;
}
